1. import { useEffect, useState } from "react";
2. import { Canvas } from "@react-three/fiber";
3. import { OrbitControls } from "@react-three/drei";
4. import * as duckdb from "@duckdb/duckdb-wasm";
5. import { bundle } from "./dbBundles";
6. import { Header } from "./components/Header";
7. import { Scene } from "./components/Scene";
8. import { DrawingSurface } from "./components/DrawingSurface";
9. import { MapView } from "./components/MapView";
10. import { StrokeEditor } from "./components/StrokeEditor";
11. 
12. // DuckDB への保存は px 座標（画面座標）で行います
13. const toWKT = (ptsPx: [number, number][]) => {
14.   // 非数値/NaN を除外して WKT を生成
15.   const filtered = ptsPx.filter(([x, y]) => Number.isFinite(x) && Number.isFinite(y));
16.   const body = filtered.map(([x, y]) => `${x} ${y}`).join(", ");
17.   return `LINESTRING(${body})`;
18. };
19. 
20. const parseLineStringFromGeoJSON = (gj: { type?: string; coordinates?: [number, number][] }): [number, number][] => {
21.   if (!gj || gj.type !== "LineString" || !gj.coordinates) return [];
22.   return gj.coordinates.map((c: [number, number]) => [c[0], c[1]]);
23. };
24. 
25. const toStr = (v: unknown): string => (typeof v === "string" ? v : v == null ? "" : String(v));
26. const toNum = (v: unknown): number => (typeof v === "number" ? v : Number(v));
27. 
28. interface Stroke {
29.   id: string;
30.   color: string;
31.   width: number; // px 単位
32.   ptsPx: [number, number][]; // DB は px 座標で保持
33. }
34. 
35. type InteractionMode = "draw" | "pan" | "edit";
36. 
37. export default function App() {
38.   const [dbConn, setDbConn] = useState<duckdb.AsyncDuckDBConnection | null>(null);
39.   const [spatialLoaded, setSpatialLoaded] = useState(false);
40.   const [loading, setLoading] = useState(true);
41.   const [strokes, setStrokes] = useState<Stroke[]>([]);
42.   const [pcdFileContents, setPcdFileContents] = useState<string[]>([]);
43.   const [interactionMode, setInteractionMode] = useState<InteractionMode>("draw");
44. 
45.   const [strokeColor, setStrokeColor] = useState("#222222");
46.   const [strokeWidth, setStrokeWidth] = useState(4);
47.   const [simplifyOn, setSimplifyOn] = useState(true);
48.   const [showMap, setShowMap] = useState(false);
49. 
50.   // DuckDB 初期化
51.   useEffect(() => {
52.     let cancelled = false;
53.     (async () => {
54.       try {
55.         setLoading(true);
56.         const worker = new Worker(bundle.mainWorker!, { type: "module" });
57.         const logger = new duckdb.ConsoleLogger();
58.         const _db = new duckdb.AsyncDuckDB(logger, worker);
59.         await _db.instantiate(bundle.mainModule, bundle.pthreadWorker);
60.         const _conn = await _db.connect();
61. 
62.         let spatialOK = false;
63.         try {
64.           await _conn.query(`INSTALL spatial;`);
65.           await _conn.query(`LOAD spatial;`);
66.           setSpatialLoaded(true);
67.           spatialOK = true;
68.         } catch (e) {
69.           console.warn("spatial extension load failed:", e);
70.           setSpatialLoaded(false);
71.         }
72. 
73.         // フォールバック用の JSON テーブルは常に用意
74.         await _conn.query(`
75.           CREATE TABLE IF NOT EXISTS strokes_json (
76.             id    TEXT PRIMARY KEY,
77.             coords JSON,
78.             color VARCHAR,
79.             width DOUBLE,
80.             created_at TIMESTAMP DEFAULT now()
81.           );
82.         `);
83. 
84.         // spatial が使える環境では GEOMETRY テーブルも作成
85.         // id は TEXT にして、ブラウザ側で UUID を付与（uuid 拡張不要）
86.         if (spatialOK) {
87.           await _conn.query(`
88.           CREATE TABLE IF NOT EXISTS strokes (
89.             id    TEXT PRIMARY KEY,
90.             geom  GEOMETRY,
91.             color VARCHAR,
92.             width DOUBLE,
93.             created_at TIMESTAMP DEFAULT now()
94.           );
95.         `);
96.         }
97. 
98.         if (!cancelled) setDbConn(_conn);
99.       } finally {
100.         if (!cancelled) setLoading(false);
101.       }
102.     })();
103.     return () => {
104.       cancelled = true;
105.     };
106.   }, []);
107. 
108.   // DB → strokes を読み直し
109.   const reloadFromDB = async () => {
110.     if (!dbConn) return;
111.     const list: Stroke[] = [];
112. 
113.     if (spatialLoaded) {
114.       const res = await dbConn.query(`
115.         SELECT id, color, width, ST_AsGeoJSON(geom) AS gj
116.         FROM strokes
117.         ORDER BY created_at ASC;
118.       `);
119.       const rows = res.toArray();
120.       for (const row of rows) {
121.         const obj = row.toJSON() as Record<string, unknown>;
122.         const id = toStr(obj["id"]);
123.         const color = toStr(obj["color"]) || "#222";
124.         const widthRaw = toNum(obj["width"]);
125.         const width = Number.isFinite(widthRaw) ? widthRaw : 3;
126.         const gj = JSON.parse(toStr(obj["gj"]));
127.         list.push({ id, color, width, ptsPx: parseLineStringFromGeoJSON(gj) });
128.       }
129.     }
130. 
131.     // JSON 方式（フォールバック/併用）
132.     const resJ = await dbConn.query(`
133.       SELECT id, color, width, coords
134.       FROM strokes_json
135.       ORDER BY created_at ASC;
136.     `);
137.     const rowsJ = resJ.toArray();
138.     for (const row of rowsJ) {
139.       const obj = row.toJSON() as Record<string, unknown>;
140.       const id = toStr(obj["id"]);
141.       const color = toStr(obj["color"]) || "#222";
142.       const widthRaw = toNum(obj["width"]);
143.       const width = Number.isFinite(widthRaw) ? widthRaw : 3;
144.       const coordsStr = toStr(obj["coords"]);
145.       let pts: [number, number][] = [];
146.       try {
147.         const a = JSON.parse(coordsStr);
148.         if (Array.isArray(a)) pts = a as [number, number][];
149.       } catch {
150.         // Ignore parsing errors, use empty array
151.       }
152.       list.push({ id, color, width, ptsPx: pts });
153.     }
154. 
155.     setStrokes(list);
156.   };
157. 
158.   useEffect(() => {
159.     if (!dbConn) return;
160.     reloadFromDB();
161.     // eslint-disable-next-line react-hooks/exhaustive-deps
162.   }, [dbConn, spatialLoaded]);
163. 
164.   // 直前のストローク削除（Undo）
165.   const handleUndo = async () => {
166.     if (!dbConn) return;
167.     if (spatialLoaded) {
168.       await dbConn.query(`
169.         DELETE FROM strokes WHERE id IN (
170.           SELECT id FROM strokes ORDER BY created_at DESC LIMIT 1
171.         );
172.       `);
173.     } else {
174.       await dbConn.query(`
175.         DELETE FROM strokes_json WHERE id IN (
176.           SELECT id FROM strokes_json ORDER BY created_at DESC LIMIT 1
177.         );
178.       `);
179.     }
180.     await reloadFromDB();
181.   };
182. 
183.   const handleClear = async () => {
184.     if (!dbConn) return;
185.     if (spatialLoaded) {
186.       await dbConn.query(`DELETE FROM strokes;`);
187.     }
188.     await dbConn.query(`DELETE FROM strokes_json;`);
189.     await reloadFromDB();
190.   };
191. 
192.   const handleRefresh = async () => reloadFromDB();
193. 
194.   // Handle PCD file loading
195.   const handleFileLoad = (event: React.ChangeEvent<HTMLInputElement>) => {
196.     const file = event.target.files?.[0];
197.     if (!file) return;
198. 
199.     if (!file.name.toLowerCase().endsWith(".pcd")) {
200.       alert("Please select a PCD file");
201.       return;
202.     }
203. 
204.     const reader = new FileReader();
205.     reader.onload = (e) => {
206.       const content = e.target?.result as string;
207.       if (content) {
208.         setPcdFileContents((prev) => [...prev, content]);
209.       }
210.     };
211.     reader.readAsText(file);
212. 
213.     // Reset the input so the same file can be loaded again
214.     event.target.value = "";
215.   };
216. 
217.   const handleClearPointClouds = () => {
218.     setPcdFileContents([]);
219.   };
220. 
221.   // 点を動かした後にストロークを更新
222.   const updateStroke = async (strokeId: string, newPtsPx: [number, number][]) => {
223.     if (!dbConn || newPtsPx.length < 2) return;
224.     if (spatialLoaded) {
225.       const wkt = String(toWKT(newPtsPx));
226.       const upd = await dbConn.prepare(`UPDATE strokes SET geom = ST_GeomFromText(CAST(? AS VARCHAR)) WHERE id = ?;`);
227.       await upd.query(wkt, strokeId);
228.       await upd.close();
229.     }
230.     const updJ = await dbConn.prepare(`UPDATE strokes_json SET coords = ? WHERE id = ?;`);
231.     await updJ.query(JSON.stringify(newPtsPx), strokeId);
232.     await updJ.close();
233.     await reloadFromDB();
234.   };
235. 
236.   // ドラッグ終了時に DB に保存
237.   const persistStroke = async (ptsPx: [number, number][]) => {
238.     if (!dbConn || ptsPx.length < 2) return;
239. 
240.     if (spatialLoaded) {
241.       const wkt = String(toWKT(ptsPx));
242.       const newId = crypto?.randomUUID?.() || Math.random().toString(36).slice(2);
243. 
244.       const insert = await dbConn.prepare(
245.         `INSERT INTO strokes(id, geom, color, width) VALUES (?, ST_GeomFromText(CAST(? AS VARCHAR)), ?, ?);`
246.       );
247.       await insert.query(newId, wkt, strokeColor, strokeWidth);
248.       await insert.close();
249. 
250.       if (simplifyOn) {
251.         const upd = await dbConn.prepare(`UPDATE strokes SET geom = ST_Simplify(geom, ?) WHERE id = ?;`);
252.         await upd.query(Math.max(0, Math.min(strokeWidth * 0.3, 3)), newId);
253.         await upd.close();
254.       }
255.     } else {
256.       const newId = crypto?.randomUUID?.() || Math.random().toString(36).slice(2);
257.       const insertJ = await dbConn.prepare(`INSERT INTO strokes_json(id, coords, color, width) VALUES (?, ?, ?, ?);`);
258.       await insertJ.query(newId, JSON.stringify(ptsPx), strokeColor, strokeWidth);
259.       await insertJ.close();
260.     }
261. 
262.     await reloadFromDB();
263.   };
264. 
265.   return (
266.     <div
267.       style={{
268.         width: "100%",
269.         height: "100%",
270.         display: "flex",
271.         flexDirection: "column",
272.         background: "#f5f5f5",
273.       }}
274.     >
275.       <Header
276.         interactionMode={interactionMode}
277.         setInteractionMode={setInteractionMode}
278.         strokeColor={strokeColor}
279.         setStrokeColor={setStrokeColor}
280.         strokeWidth={strokeWidth}
281.         setStrokeWidth={setStrokeWidth}
282.         simplifyOn={simplifyOn}
283.         setSimplifyOn={setSimplifyOn}
284.         handleUndo={handleUndo}
285.         handleRefresh={handleRefresh}
286.         handleClear={handleClear}
287.         handleFileLoad={handleFileLoad}
288.         handleClearPointClouds={handleClearPointClouds}
289.         pcdFileContents={pcdFileContents}
290.         showMap={showMap}
291.         setShowMap={setShowMap}
292.       />
293. 
294.       <main style={{ flex: 1, padding: 12, minHeight: 0 }}>
295.         {/* 親は高さを持つだけ。装飾は持たせない */}
296.         <div style={{ position: "relative", width: "100%", height: "100%" }}>
297.           {/* Canvas は absolute で inset:0（%高さ連鎖を断つ） */}
298.           <div style={{ position: "absolute", inset: 0 }}>
299.             {showMap ? (
300.               <MapView visible={showMap} />
301.             ) : (
302.               <Canvas
303.                 orthographic
304.                 camera={{ position: [0, 0, 100], zoom: 1 }}
305.                 style={{ width: "100%", height: "100%" }}
306.               >
307.                 <color attach="background" args={["#ffffff"]} />
308.                 <ambientLight intensity={0.5} />
309.                 {/* 画面操作 - OrbitControls behavior changes based on interaction mode */}
310.                 <OrbitControls makeDefault enableRotate={false} enabled={interactionMode === "pan"} />
311. 
312.                 <Scene pcdFileContents={pcdFileContents} strokes={strokes} hideStrokes={interactionMode === "edit"} />
313.                 <StrokeEditor strokes={strokes} onUpdateStroke={updateStroke} enabled={interactionMode === "edit"} />
314.                 <DrawingSurface
315.                   onFinish={persistStroke}
316.                   color={strokeColor}
317.                   width={strokeWidth}
318.                   enabled={interactionMode === "draw"}
319.                 />
320.               </Canvas>
321.             )}
322.           </div>
323. 
324.           {/* ローディング/警告オーバーレイ */}
325.           {loading && (
326.             <div
327.               style={{
328.                 position: "absolute",
329.                 inset: 0,
330.                 display: "grid",
331.                 placeItems: "center",
332.                 fontSize: 12,
333.                 color: "#666",
334.               }}
335.             >
336.               DuckDB を初期化中…
337.             </div>
338.           )}
339.           {!loading && !spatialLoaded && (
340.             <div
341.               style={{
342.                 position: "absolute",
343.                 inset: 0,
344.                 display: "grid",
345.                 placeItems: "center",
346.                 fontSize: 12,
347.                 color: "#b45309",
348.                 padding: 16,
349.                 textAlign: "center",
350.               }}
351.             >
352.               spatial 拡張のロードに失敗しました。環境によっては利用できない場合があります。
353.               <br />
354.               その場合、保存・再描画が動作しません（コンソールのログをご確認ください）。
355.             </div>
356.           )}
357. 
358.           {/* 枠の装飾はオーバーレイに分離 */}
359.           <div
360.             style={{
361.               position: "absolute",
362.               inset: 0,
363.               pointerEvents: "none",
364.               borderRadius: 16,
365.               boxShadow: "0 1px 8px rgba(0,0,0,.05)",
366.               border: "1px solid #e5e5e5",
367.             }}
368.           />
369.         </div>
370.       </main>
371. 
372.       <footer style={{ padding: 8, fontSize: 12, color: "#666", textAlign: "right" }}>
373.         Draw モード: クリックで点を追加・Escで確定 | Edit モード: 点をドラッグで移動 | Pan モード:
374.         ドラッグで移動・ホイールでズーム | PCDファイル読み込み対応 | Undo・Clear はヘッダーから
375.       </footer>
376.     </div>
377.   );
378. }
379.

