                 <StrokeEditor strokes={strokes} onUpdateStroke={updateStroke} enabled={interactionMode === "edit"} />
                 <DrawingSurface
                   onFinish={persistStroke}
                   color={strokeColor}
                   width={strokeWidth}
                   enabled={interactionMode === "draw"}
                 />
               </Canvas>
             )}
           </div>

           {/* ローディング/警告オーバーレイ */}
           {loading && (
             <div
               style={{
                 position: "absolute",
                 inset: 0,
                 display: "grid",
                 placeItems: "center",
                 fontSize: 12,
                 color: "#666",
               }}
             >
               DuckDB を初期化中…
             </div>
           )}
           {!loading && !spatialLoaded && (
             <div
               style={{
                 position: "absolute",
                 inset: 0,
                 display: "grid",
                 placeItems: "center",
                 fontSize: 12,
                 color: "#b45309",
                 padding: 16,
                 textAlign: "center",
               }}
             >
               spatial 拡張のロードに失敗しました。環境によっては利用できない場合があります。
               <br />
               その場合、保存・再描画が動作しません（コンソールのログをご確認ください）。
             </div>
           )}

           {/* 枠の装飾はオーバーレイに分離 */}
           <div
             style={{
               position: "absolute",
               inset: 0,
               pointerEvents: "none",
               borderRadius: 16,
               boxShadow: "0 1px 8px rgba(0,0,0,.05)",
               border: "1px solid #e5e5e5",
             }}
           />
         </div>
       </main>

       <footer style={{ padding: 8, fontSize: 12, color: "#666", textAlign: "right" }}>
         Draw モード: クリックで点を追加・Escで確定 | Edit モード: 点をドラッグで移動 | Pan モード:
         ドラッグで移動・ホイールでズーム | PCDファイル読み込み対応 | Undo・Clear はヘッダーから
       </footer>
     </div>
   );
 }

